    fn typecheck_rejects_int_match_without_default() {
        let err = typecheck_src(
            r#"
            let n = 5;
            let r = match n { 0 => "zero", 1 => "one", };
        "#,
        )
        .unwrap_err();
        assert!(err.contains("Non-exhaustive match on int"), "got: {}", err);
    }

