    // ---------- RES-429: string_pad_left / string_pad_right ----------

    fn pad_call(f: fn(&[Value]) -> RResult<Value>, s: &str, w: i64, pad: &str) -> Value {
        f(&[
            Value::String(s.into()),
            Value::Int(w),
            Value::String(pad.into()),
        ])
        .unwrap()
    }

    #[test]
    fn string_pad_left_basic() {
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_left, "42", 5, "0")),
            "00042"
        );
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_left, "hi", 5, " ")),
            "   hi"
        );
    }

    #[test]
    fn string_pad_right_basic() {
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_right, "hi", 5, ".")),
            "hi..."
        );
    }

    #[test]
    fn string_pad_already_wide_returns_unchanged() {
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_left, "abcdef", 3, "0")),
            "abcdef"
        );
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_right, "abcdef", 6, "0")),
            "abcdef"
        );
    }

    #[test]
    fn string_pad_zero_width() {
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_left, "x", 0, "0")),
            "x"
        );
    }

    #[test]
    fn string_pad_unicode_width_counts_chars_not_bytes() {
        // "café" is 4 chars but 5 UTF-8 bytes. Padding to width 6 must
        // produce 4 + 2 chars worth, not byte-count math.
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_left, "café", 6, "_")),
            "__café"
        );
    }

    #[test]
    fn string_pad_with_unicode_pad_char() {
        assert_eq!(
            extract_string(pad_call(builtin_string_pad_right, "x", 4, "✓")),
            "x✓✓✓"
        );
    }

    #[test]
    fn string_pad_rejects_negative_width() {
        let err = builtin_string_pad_left(&[
            Value::String("a".into()),
            Value::Int(-1),
            Value::String("0".into()),
        ])
        .unwrap_err();
        assert!(err.contains("non-negative"), "got: {}", err);
    }

    #[test]
    fn string_pad_rejects_non_single_char_pad() {
        let err = builtin_string_pad_right(&[
            Value::String("a".into()),
            Value::Int(5),
            Value::String("ab".into()),
        ])
        .unwrap_err();
        assert!(err.contains("single character"), "got: {}", err);
        let err = builtin_string_pad_left(&[
            Value::String("a".into()),
            Value::Int(5),
            Value::String("".into()),
        ])
        .unwrap_err();
        assert!(err.contains("single character"), "got: {}", err);
    }

    #[test]
    fn string_pad_rejects_wrong_types_and_arity() {
        assert!(
            builtin_string_pad_left(&[Value::Int(1), Value::Int(5), Value::String("0".into())])
                .unwrap_err()
                .contains("expected (string, int, string)")
        );
        assert!(
            builtin_string_pad_right(&[Value::String("a".into())])
                .unwrap_err()
                .contains("expected 3 arguments")
        );
    }

    // ---------- RES-430: array_zip ----------

    fn extract_tuples(v: Value) -> Vec<(Value, Value)> {
        match v {
            Value::Array(items) => items
                .into_iter()
                .map(|t| match t {
                    Value::Tuple(xs) if xs.len() == 2 => (xs[0].clone(), xs[1].clone()),
                    other => panic!("expected 2-tuple, got {:?}", other),
                })
                .collect(),
            _ => panic!("expected Array"),
        }
    }

    #[test]
    fn array_zip_pairs_elements() {
        let pairs = extract_tuples(
            builtin_array_zip(&[int_array(&[1, 2, 3]), int_array(&[10, 20, 30])]).unwrap(),
        );
        assert_eq!(pairs.len(), 3);
        for (i, (a, b)) in pairs.iter().enumerate() {
            match (a, b) {
                (Value::Int(x), Value::Int(y)) => {
                    assert_eq!(*x, (i + 1) as i64);
                    assert_eq!(*y, (i + 1) as i64 * 10);
                }
                _ => panic!("non-int in tuple"),
            }
        }
    }

    #[test]
    fn array_zip_truncates_to_shorter() {
        let pairs = extract_tuples(
            builtin_array_zip(&[int_array(&[1, 2, 3, 4, 5]), int_array(&[10, 20])]).unwrap(),
        );
        assert_eq!(pairs.len(), 2);
        let pairs = extract_tuples(
            builtin_array_zip(&[int_array(&[1]), int_array(&[10, 20, 30])]).unwrap(),
        );
        assert_eq!(pairs.len(), 1);
    }

    #[test]
    fn array_zip_empty_inputs_return_empty() {
        let pairs =
            extract_tuples(builtin_array_zip(&[Value::Array(vec![]), int_array(&[1, 2])]).unwrap());
        assert!(pairs.is_empty());
        let pairs =
            extract_tuples(builtin_array_zip(&[int_array(&[1, 2]), Value::Array(vec![])]).unwrap());
        assert!(pairs.is_empty());
        let pairs = extract_tuples(
            builtin_array_zip(&[Value::Array(vec![]), Value::Array(vec![])]).unwrap(),
        );
        assert!(pairs.is_empty());
    }

    #[test]
    fn array_zip_heterogeneous_types() {
        // First array: Int. Second: String.
        let result = builtin_array_zip(&[
            Value::Array(vec![Value::Int(1), Value::Int(2)]),
            Value::Array(vec![Value::String("a".into()), Value::String("b".into())]),
        ])
        .unwrap();
        match result {
            Value::Array(items) => {
                assert_eq!(items.len(), 2);
                match &items[0] {
                    Value::Tuple(xs) if xs.len() == 2 => match (&xs[0], &xs[1]) {
                        (Value::Int(1), Value::String(s)) => assert_eq!(s, "a"),
                        other => panic!("unexpected first tuple: {:?}", other),
                    },
                    other => panic!("expected 2-tuple, got {:?}", other),
                }
            }
            other => panic!("expected Array, got {:?}", other),
        }
    }

    #[test]
    fn array_zip_rejects_non_array_and_arity() {
        assert!(
            builtin_array_zip(&[Value::Int(1), Value::Array(vec![])])
                .unwrap_err()
                .contains("expected (array, array)")
        );
        assert!(
            builtin_array_zip(&[Value::Array(vec![])])
                .unwrap_err()
                .contains("expected 2 arguments")
        );
    }

