    // ---------- RES-435: array_chunk ----------

    fn extract_chunks(v: Value) -> Vec<Vec<i64>> {
        match v {
            Value::Array(outer) => outer
                .into_iter()
                .map(|inner| match inner {
                    Value::Array(items) => items
                        .into_iter()
                        .map(|v| match v {
                            Value::Int(n) => n,
                            _ => panic!("non-int element"),
                        })
                        .collect(),
                    _ => panic!("non-array chunk"),
                })
                .collect(),
            _ => panic!("expected outer Array"),
        }
    }

